<template><app-content class="h-panel payroll-page"><div class="h-panel-bar"><span class="h-panel-title">工资计算</span></div><div class="margin-top margin-left payroll-toolbar"><NumberInput v-model="year" placeholder="年度"></NumberInput><NumberInput v-model="month" placeholder="月份"></NumberInput><Button color="primary" @click="calculate">计算工资</Button></div><div class="h-panel-body"><Table :datas="rows" :border="true"><TableItem title="工号" prop="employeeNo"></TableItem><TableItem title="姓名" prop="employeeName"></TableItem><TableItem title="部门" prop="departmentName"></TableItem><TableItem title="基本工资" prop="BASE_SALARY"></TableItem><TableItem title="社保" prop="SOCIAL_SECURITY"></TableItem><TableItem title="公积金" prop="HOUSING_FUND"></TableItem><TableItem title="个税" prop="IIT"></TableItem><TableItem title="实发工资" prop="NET_PAY"></TableItem></Table></div></app-content></template>
<script>import payroll from '../../api/payroll'; const d = new Date(); export default { name: 'PayrollCalculate', data() { return {year: d.getFullYear(), month: d.getMonth() + 1, rows: []} }, methods: { calculate() { payroll.sheet.calculate(this.year, this.month).then(({data}) => this.rows = data || []) } } }</script>
<style scoped>.payroll-toolbar>*{margin-right:8px}</style>
